board_copy = [row[:] for row in board]

# Solve the Sudoku
if solve_sudoku(board_copy):
    print("Sudoku solved successfully!")
    print("Solution:")
    for row in board_copy:
        print(' '.join(map(str, row)))
else:
    print("No solution exists")



